3	export interface DbPool {
4	  readonly writer: Database.Database;
5	  reader(): Database.Database;
6	  close(): void;
7	  /**
8	   * Runs fn inside a single BEGIN/COMMIT transaction on the writer connection.
9	   * If fn throws, the transaction is rolled back and the exception is re-thrown
10	   * to the caller without wrapping. Returns the value returned by fn.
11	   *
12	   * No catch block — better-sqlite3 handles rollback-on-throw internally.
13	   */
14	  transaction<T>(fn: (db: Database.Database) => T): T;
15	}
16	
17	/**
18	 * PRAGMAs applied to the writer connection.
19	 * busy_timeout is first so it protects even the schema_migrations bootstrap
20	 * from SQLITE_BUSY before migrations run.
21	 */
22	function applyWriterPragmas(db: Database.Database): void {
23	  db.pragma('busy_timeout = 5000');
24	  db.pragma('journal_mode = WAL');
25	  db.pragma('synchronous = NORMAL');
26	  db.pragma('foreign_keys = ON');
27	}
28	
29	/**
30	 * PRAGMAs applied to read-only connections.
31	 * journal_mode is already WAL (inherited from the database file written by
32	 * the writer); attempting to set it on a readonly connection is skipped to
33	 * avoid a potential SQLITE_READONLY error on some SQLite builds.
34	 * synchronous is omitted for the same reason — readers don't fsync writes.
35	 */
36	function applyReaderPragmas(db: Database.Database): void {
37	  db.pragma('busy_timeout = 5000');
38	  db.pragma('foreign_keys = ON');
39	}
40	
41	/**
42	 * Creates the schema_migrations bootstrap table idempotently.
43	 * Uses CREATE TABLE IF NOT EXISTS so a second call on an already-migrated
44	 * database is a no-op.
45	 */
46	function bootstrapMigrationsTable(db: Database.Database): void {
47	  db.exec(`
48	    CREATE TABLE IF NOT EXISTS schema_migrations (
49	      version   INTEGER PRIMARY KEY,
50	      applied_at TEXT NOT NULL
51	    )
52	  `);
53	}
54	
55	/**
56	 * Opens the database at dbPath and returns a DbPool.
57	 *
58	 * - writer: single read-write connection with all four PRAGMAs set.
59	 * - reader(): returns a pre-opened read-only connection; enforced at the
60	 *   connection level via { readonly: true }, not by convention.
61	 * - close(): closes both connections.
62	 *
63	 * No module-level singleton is exported. Callers must inject this pool.
64	 */
65	export function openDbPool(dbPath: string): DbPool {
66	  const writer = new Database(dbPath);
67	  applyWriterPragmas(writer);         // busy_timeout set BEFORE migrations
68	  bootstrapMigrationsTable(writer);
69	
70	  const readerConn = new Database(dbPath, { readonly: true });
71	  applyReaderPragmas(readerConn);
72	
73	  return {
74	    writer,
75	    reader(): Database.Database {
76	      return readerConn;
77	    },
78	    close(): void {
79	      readerConn.close();
80	      writer.close();
81	    },
82	    transaction<T>(fn: (db: Database.Database) => T): T {
83	      return writer.transaction(fn)(writer);
84	    },
85	  };
